int dp1[N][4], dp2[N][4], pre1[N], pre0[N];
void solve(int CASE)
{
	int n; cin >> n;
	string s; cin >> s; s = ' ' + s;
	fa(i, 1, n)pre1[i] = pre1[i - 1] + (s[i] == '1');
	fa(i, 1, n)pre0[i] = pre0[i - 1] + (s[i] == '0');
	fa(i, 0, n)fa(j, 0, 3)dp1[i][j] = dp2[i][j] = INF;
	var st1 = vector<int>{ 0,1,0,1 };
	var st2 = vector<int>{ 1,0,1,0 };
	if (s[1] == '1') {
		dp1[1][0] = 1;
		dp2[1][0] = 0;
	}
	else {
		dp1[1][0] = 0;
		dp2[1][0] = 1;
	}
	fa(i, 2, n) {
		// [j, i - 1]
		fa(j, 1, i - 1)fa(k, 0, 2) {
			// 1
			if (st1[k + 1])
				dp1[i][k + 1] = dp1[j][k] + (pre1[i - 1] - pre1[j]) + (s[i] == '0');
			else
				dp1[i][k + 1] = dp1[j][k] + (pre0[i - 1] - pre0[j]) + (s[i] == '1');

			// 2
			if (st2[k + 1])
				dp2[i][k + 1] = dp2[j][k] + (pre1[i - 1] - pre1[j]) + (s[i] == '0');
			else
				dp2[i][k + 1] = dp2[j][k] + (pre0[i - 1] - pre0[j]) + (s[i] == '1');
		}

		// [j, i]
		fa(j, 1, i - 1)fa(k, 0, 3) {
			// 1
			if (st1[k])
				dp1[i][k] = min(dp1[i][k], dp1[j][k] + (pre0[i] - pre0[j]));
			else
				dp1[i][k] = min(dp1[i][k], dp1[j][k] + (pre1[i] - pre1[j]));

			// 2
			if (st2[k])
				dp2[i][k] = min(dp2[i][k], dp2[j][k] + (pre0[i] - pre0[j]));
			else
				dp2[i][k] = min(dp2[i][k], dp2[j][k] + (pre1[i] - pre1[j]));
		}
	}

	cout << min(dp1[n][3], dp2[n][3]) << endl;
	return;
}
